  function escapeHtml(value) {
    return String(value || "")
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;")
      .replace(/'/g, "&#39;");
  }

  function linkify(value) {
    return escapeHtml(value).replace(/(https?:\/\/[^\s<]+)/g, (url) => `<a class="source-url" href="${url}" target="_blank" rel="noreferrer">${url}</a>`);
  }

  function compact(value) {
    return String(value || "").replace(/\s+/g, " ").trim();
  }

  function renderPracticeItem(item, index, mode, placeholder) {
    return `
      <article class="practice-item" data-practice-check data-practice-mode="${escapeHtml(mode || "zh")}">
        <div class="practice-head">
          <span class="practice-no">${String(index + 1).padStart(2, "0")}</span>
          ${item.source ? `<span class="practice-source">${escapeHtml(item.source)}</span>` : ""}
        </div>
        <p class="practice-prompt">${escapeHtml(item.prompt)}</p>
        <textarea data-practice-input placeholder="${escapeHtml(placeholder || "在这里输入你的答案")}"></textarea>
        <div class="practice-controls">
          <button class="practice-check-button" type="button" data-practice-action>自检覆盖度</button>
          <span class="practice-result" data-practice-result aria-live="polite"></span>
        </div>
        <details class="answer-detail">
          <summary>显示参考答案</summary>
          <p data-practice-answer>${escapeHtml(item.answer)}</p>
        </details>
      </article>
    `;
  }

  function renderTranslationUnit(unit) {
    const items = unit.items.map((item, index) => renderPracticeItem(item, index, "zh", "先自己翻译，再点击自检覆盖度")).join("");
    return `
      <div class="reply">
        <section class="tldr">
          <h2>${escapeHtml(unit.title)}</h2>
          <p>默认只显示英文原句。输入自己的译文后点击自检，再展开参考译文核对术语、逻辑关系和信息完整度。</p>
        </section>
        <div class="source-meta">
          <span>${escapeHtml(unit.unit)}</span>
          <span>${unit.items.length} 道翻译题</span>
          <span>来源：${escapeHtml(unit.source)}</span>
        </div>
        <section class="practice-list">
          ${items}
        </section>
      </div>
    `;
  }

  function headlineRuleNotes(group) {
    if (group.slug === "press-headline-compression") {
      return [
        "先抓主语、核心动词、结果和地点/原因等新闻要素，删去可省略的冠词、助动词和冗余修饰。",
        "被动意义常保留过去分词，未来安排常用 to do，正在发生或趋势性动作可用现在分词。",
        "标题应简洁、准确、醒目，避免把完整句机械缩短成不自然的短语。"
      ];
    }
    if (group.slug === "press-headline-restoration") {
      return [
        "还原时补出冠词、be 动词、助动词、连接词和必要代词，使句子语法完整。",
        "注意标题中的 to do 多表示将来，过去分词常表示被动，现在分词常表示进行或持续状态。",
        "还原完整句时可以适当调整词序，但不能改变新闻事实。"
      ];
    }
    return [
      "中文翻译应优先传达新闻事实和标题语气，不必逐字对应英文结构。",
      "遇到隐含的 be、冠词或连接关系，要在中文里自然补足。",
      "中文标题可更凝练，但必须保留人物、事件、结果和态度等关键信息。"
    ];
  }

  function renderHeadlineCategoryLinks() {
    return pressData.headlineGroups.map((group) => `
      <a class="headline-category-link" href="${escapeHtml(group.slug)}.html">
        <strong>${escapeHtml(group.title)}</strong>
        <span>${group.items.length} 道自测题</span>
      </a>
    `).join("");
  }

  function renderHeadlineGroupPage(group) {
    return `
      <div class="reply">
        <section class="tldr">
          <h2>${escapeHtml(group.title)}</h2>
          <p>${escapeHtml(group.hint)}</p>
        </section>
        <div class="source-meta">
          <span>${group.items.length} 道练习</span>
          <span>来源：英语新闻标题的改写练习.pdf</span>
          <a href="press-headline-rewriting-practice.html">打开综合自测</a>
        </div>
        <section class="note">
          <h3>自检要点</h3>
          <ul>
            ${headlineRuleNotes(group).map((item) => `<li>${escapeHtml(item)}</li>`).join("")}
          </ul>
        </section>
        <section class="practice-list">
          ${group.items.map((item, index) => renderPracticeItem(item, index, group.mode, group.mode === "zh" ? "输入中文译文" : "输入英文改写句")).join("")}
        </section>
      </div>
    `;
  }

  function renderHeadlinePractice() {
    const groups = pressData.headlineGroups.map((group) => `
      <section class="style-section">
        <h3>${escapeHtml(group.title)}</h3>
        <p>${escapeHtml(group.hint)}</p>
        <div class="practice-list">
          ${group.items.map((item, index) => renderPracticeItem(item, index, group.mode, group.mode === "zh" ? "输入中文译文" : "输入英文改写句")).join("")}
        </div>
      </section>
    `).join("");

    return `
      <div class="reply">
        <section class="tldr">
          <h2>新闻标题改写自测</h2>
          <p>根据 PDF 练习整理为 A/B/C 三组：完整句压缩为标题、标题还原完整句、标题中文翻译。答案默认隐藏。</p>
        </section>
        <section class="headline-category-grid" aria-label="标题改写分类练习">
          ${renderHeadlineCategoryLinks()}
        </section>
        <section class="note">
          <h3>标题改写提醒</h3>
          <ul>
            <li>标题常省略冠词、连词、代词和 be 动词。</li>
            <li>将来意义常用 <strong>to + verb</strong>，进行意义常用现在分词。</li>
            <li>被动语态常省略 <strong>be</strong>，但还原完整句时要补出。</li>
          </ul>
        </section>
        <div class="style-guide">${groups}</div>
      </div>
    `;
  }

