  function renderPressLeadExample(entry, index) {
    return `
      <div class="reply press-lead-example">
        <section class="tldr">
          <h2>${escapeHtml(entry.title)}</h2>
          <p>根据虚构新闻材料练习 summary lead writing，重点看哪些信息进入第一句，哪些信息留到正文第二段。</p>
        </section>
        <div class="source-meta">
          <span>来源：新闻导语例子.md</span>
          <span>${escapeHtml(entry.sourceType)}</span>
          <span>例子 ${String(index + 1).padStart(2, "0")} / ${pressLeadExampleEntries.length}</span>
        </div>
        <section class="press-lead-rule-card">
          <div class="case-example-section-head">
            <p class="section-kicker">Lead Writing Rules / 写法原则</p>
            <h2>先写最有新闻价值的信息</h2>
          </div>
          <ul>
            ${pressLeadPrinciples.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}
          </ul>
        </section>
        <section class="press-lead-source">
          <div class="case-example-section-head">
            <p class="section-kicker">News Paragraph / 新闻材料</p>
            <h2>原始新闻事实</h2>
          </div>
          <p>${escapeHtml(entry.newsParagraph)}</p>
        </section>
        <section class="press-lead-output">
          <div class="case-example-section-head">
            <p class="section-kicker">Lead / 导语</p>
            <h2>英文导语与中文导语</h2>
          </div>
          <div class="press-lead-pair">
            <article>
              <span>English Lead</span>
              <p>${escapeHtml(entry.leadEn)}</p>
            </article>
            <article>
              <span>中文导语</span>
              <p>${escapeHtml(entry.leadZh)}</p>
            </article>
          </div>
        </section>
        <section class="press-lead-analysis">
          <div class="case-example-section-head">
            <p class="section-kicker">Analysis / 分析</p>
            <h2>为什么这样写</h2>
          </div>
          <p>${escapeHtml(entry.analysis)}</p>
        </section>
        <section class="press-lead-steps">
          <div class="case-example-section-head">
            <p class="section-kicker">Reusable Pattern / 可套用结构</p>
            <h2>写作步骤</h2>
          </div>
          <ol>
            ${pressLeadSteps.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}
          </ol>
          <div class="press-lead-formula">
            <strong>${escapeHtml(pressLeadPattern.en)}</strong>
            <p>${escapeHtml(pressLeadPattern.example)}</p>
            <p>${escapeHtml(pressLeadPattern.zh)}</p>
          </div>
        </section>
      </div>
    `;
  }

  function isDocumentHeading(paragraph) {
    const text = compact(paragraph);
    if (!text || /^\d+[.)]/.test(text)) return false;
    if (/^(Source|Title|Date|Verified URL|Publication Date|Story Source|Journal Reference|CITATIONS|About|Related Stories|Notes|Words and expressions|Reading comprehension questions|课堂讨论题|深度分析题|Discussion|Passage \d|Reading \d)/i.test(text)) return true;
    if (/^(The many different AI races|The global landscape|The next AI races|Good news\/bad news|Picking plastics apart|False advertising|Making plastics mix|Good as new|Microbial help|Milder conditions|Built to last|An Accidental Ink|Qualcomm wants|There’s a new record|CHEMISTRY)$/i.test(text)) return true;
    return text.length <= 72 && !/[.!?。！？]$/.test(text) && /[A-Za-z\u4e00-\u9fff]/.test(text);
  }

  function renderDocumentBody(body) {
    return String(body || "")
      .replace(/\r/g, "")
      .replace(/\[[^\]\n]*(?:jpg|png|IMG|pic)[^\]\n]*\]/gi, "")
      .split(/\n\s*\n+/)
      .map((paragraph) => paragraph.trim())
      .filter((paragraph) => paragraph && paragraph !== "[]" && paragraph !== "窗体底端")
      .map((paragraph) => isDocumentHeading(paragraph) ? `<h3>${escapeHtml(compact(paragraph))}</h3>` : `<p>${linkify(paragraph)}</p>`)
      .join("");
  }

  function renderReading(reading) {
    return `
      <div class="reply">
        <section class="tldr">
          <h2>${escapeHtml(reading.title)}</h2>
          <p>${escapeHtml(reading.unit)} 阅读材料，已保留原文、术语/注释和课后问题，供综合阅读与写作复习。</p>
        </section>
        <div class="source-meta">
          <span>${escapeHtml(reading.unit)}</span>
          <span>${escapeHtml(reading.source)}</span>
          <span>来源文件：${escapeHtml(reading.file)}</span>
        </div>
        <article class="source-document">
          <div class="source-doc-body">${renderDocumentBody(reading.body)}</div>
        </article>
      </div>
    `;
  }

  function renderStylePage(page) {
    const sections = page.sections.map((section) => `
      <section class="style-section">
        <h3>${escapeHtml(section.title)}</h3>
        ${section.points && section.points.length ? `<ul>${section.points.map((point) => `<li>${escapeHtml(point)}</li>`).join("")}</ul>` : ""}
        ${section.examples && section.examples.length ? `<ul class="example-list">${section.examples.map((example) => `<li>${escapeHtml(example)}</li>`).join("")}</ul>` : ""}
      </section>
    `).join("");

    return `
      <div class="reply">
        <section class="tldr">
          <h2>${escapeHtml(page.title)}</h2>
          <p>${escapeHtml(page.lead)}</p>
        </section>
        <div class="source-meta">
          <span>${escapeHtml(page.slides)}</span>
          <span>来源：新闻语体特征.pptx</span>
        </div>
        <div class="style-guide">${sections}</div>
      </div>
    `;
  }

  function renderKnowledgeTable(table) {
    if (!table) return "";
    const headers = table.headers.map((header) => `<th>${escapeHtml(header)}</th>`).join("");
    const rows = table.rows.map((row) => `
      <tr>${row.map((cell) => `<td>${escapeHtml(cell)}</td>`).join("")}</tr>
    `).join("");
    return `
      <div class="term-table-wrap">
        <table class="term-table">
          <thead><tr>${headers}</tr></thead>
          <tbody>${rows}</tbody>
        </table>
      </div>
    `;
  }

  function knowledgePointMarkup(point) {
    if (point && typeof point === "object") {
      return `
        <li class="bilingual-point">
          <span>${escapeHtml(point.en || point.text || "")}</span>
          ${point.zh ? `<small>${escapeHtml(point.zh)}</small>` : ""}
        </li>
      `;
    }
    return `<li>${escapeHtml(point)}</li>`;
  }

  function knowledgeListMarkup(items, className) {
    if (!items || !items.length) return "";
    const isBilingual = items.some((item) => item && typeof item === "object");
    const classes = [className, isBilingual ? "bilingual-list" : ""].filter(Boolean).join(" ");
    return `<ul${classes ? ` class="${classes}"` : ""}>${items.map(knowledgePointMarkup).join("")}</ul>`;
  }

  function renderKnowledgePage(page) {
    const sections = page.sections.map((section) => `
      <section class="style-section">
        <h3>${escapeHtml(section.title)}</h3>
        ${renderKnowledgeTable(section.table)}
        ${knowledgeListMarkup(section.points)}
        ${knowledgeListMarkup(section.examples, "example-list")}
      </section>
    `).join("");

    return `
      <div class="reply press-knowledge">
        <section class="tldr">
          <h2>${escapeHtml(page.title)}</h2>
          <p>${escapeHtml(page.lead)}</p>
        </section>
        <div class="source-meta">
          <span>来源：${escapeHtml(page.source)}</span>
          <span>${page.sections.length} 组知识</span>
        </div>
        <div class="style-guide">${sections}</div>
      </div>
    `;
  }

